package dev.aperture.editor.imgui;
import dev.aperture.editor.model.command.ExpectedRevision;import imgui.ImGui;
final class RuntimeWindow{private final ApertureUiContext c;RuntimeWindow(ApertureUiContext c){this.c=c;}void render(){if(!ImGui.begin("Context Runtime")){ImGui.end();return;}var id=c.session.selection().snapshot().primaryObject();if(id==null)ImGui.textDisabled("Select an object to inspect runtime state");else c.session.readModel().object(id).ifPresentOrElse(v->{ImGui.text(v.displayName()+" Status");ImGui.separator();v.runtimeState().values().forEach((key,value)->{ImGui.textDisabled(key);ImGui.sameLine(ApertureStyle.LABEL_WIDTH);ImGui.text(String.valueOf(value));});for(var action:v.runtimeActions()){ImGui.textDisabled(action.group());boolean disabled=!action.enabled()||action.pending();if(disabled)ImGui.beginDisabled();boolean pressed=ImGui.button(action.label()+"##"+action.id());if(disabled)ImGui.endDisabled();if(pressed)c.session.commands().submitRuntimeAction(v.objectId(),action.id(),new ExpectedRevision(v.objectRevision(),v.stateRevision()));}},()->ImGui.textDisabled("Replica unavailable"));ImGui.end();}}
